import requests

# Параметри запиту
params = {'userId': 1}
resp = requests.get('https://jsonplaceholder.typicode.com/posts', params=params)
posts = resp.json()
print(f'Постів користувача 1: {len(posts)}')

# Обробка помилок
try:
    resp = requests.get('https://jsonplaceholder.typicode.com/nonexistent', timeout=5)
    resp.raise_for_status()
except requests.exceptions.HTTPError as e:
    print(f'HTTP помилка: {e}')
except requests.exceptions.ConnectionError:
    print('Помилка з\'єднання')
except requests.exceptions.Timeout:
    print('Час вичерпано')
